/**
 * Script to generate test images for E2E tests
 * Run with: npx tsx generate-test-images.ts
 */

import { writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));

// Minimal 1x1 pixel PNG (transparent)
const MINIMAL_PNG_BASE64 =
  'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==';

// Minimal 100x100 pixel colored PNG (green)
const GREEN_PNG_100x100_BASE64 =
  '';

// Minimal 200x200 pixel colored PNG (blue) for hero/larger images
const BLUE_PNG_200x200_BASE64 =
  '';

// Minimal favicon.ico (16x16 transparent)
const FAVICON_ICO_BASE64 =
  '';

// Generate test images
const images = [
  { name: 'test-logo-light.png', data: GREEN_PNG_100x100_BASE64 },
  { name: 'test-logo-dark.png', data: GREEN_PNG_100x100_BASE64 },
  { name: 'test-hero.jpg', data: BLUE_PNG_200x200_BASE64 }, // PNG works as test image
  { name: 'test-founder.jpg', data: GREEN_PNG_100x100_BASE64 },
  { name: 'test-og-image.png', data: BLUE_PNG_200x200_BASE64 },
  { name: 'test-favicon.ico', data: FAVICON_ICO_BASE64 },
  { name: 'test-brand-pillar.png', data: GREEN_PNG_100x100_BASE64 },
  { name: 'test-event-image.png', data: BLUE_PNG_200x200_BASE64 },
  { name: 'test-testimonial-photo.png', data: MINIMAL_PNG_BASE64 },
  { name: 'test-destination-image.png', data: BLUE_PNG_200x200_BASE64 },
  { name: 'test-partner-logo.png', data: GREEN_PNG_100x100_BASE64 },
];

console.log('Generating test images...\n');

for (const image of images) {
  const filePath = join(__dirname, image.name);
  const buffer = Buffer.from(image.data, 'base64');
  writeFileSync(filePath, buffer);
  console.log(`Created: ${image.name} (${buffer.length} bytes)`);
}

console.log('\nDone! All test images generated.');
